<?php get_header(); ?>
<?php while (have_posts()) : the_post(); ?>
<article <?php post_class(); ?>><header class="page-hero"><div class="container"><?php wazzaapi_breadcrumb(); ?><div class="post-meta"><?php echo esc_html(get_the_date()); ?> · <?php echo esc_html(wazzaapi_reading_time()); ?> · <?php the_author(); ?></div><h1 class="page-title"><?php the_title(); ?></h1><?php if (has_excerpt()) : ?><p class="lead"><?php echo esc_html(get_the_excerpt()); ?></p><?php endif; ?></div></header><?php if (has_post_thumbnail()) : ?><div class="container featured-image-wrap"><?php the_post_thumbnail('large'); ?></div><?php endif; ?><section class="section"><div class="container"><div class="entry-content"><?php the_content(); wp_link_pages(); ?></div></div></section></article>
<?php endwhile; get_footer(); ?>
